def main():
    parser = build_parser()
    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        sys.exit(1)

    if args.verbose:
        logging.getLogger().setLevel(logging.DEBUG)

    bootstrap_servers = args.bootstrap_servers.split(",")

    admin_client = create_admin_client(
        bootstrap_servers=bootstrap_servers,
        security_protocol=args.security_protocol,
        sasl_mechanism=args.sasl_mechanism,
        sasl_username=args.sasl_username,
        sasl_password=args.sasl_password,
    )

    success = True

    try:
        if args.command == "create-topic":
            topic_config = parse_config_string(args.config)
            topics_config = [
                {
                    "name": args.topic,
                    "num_partitions": args.partitions,
                    "replication_factor": args.replication_factor,
                    "config": topic_config,
                }
            ]
            success = create_topics(admin_client, topics_config)

        elif args.command == "create-topics-from-file":
            try:
                with open(args.file, "r") as f:
                    topics_config = json.load(f)
                if not isinstance(topics_config, list):
                    logger.error("JSON file must contain a list of topic configurations")
                    sys.exit(1)
                success = create_topics(admin_client, topics_config)
            except (json.JSONDecodeError, FileNotFoundError) as e:
                logger.error("Failed to read topics file '%s': %s", args.file, e)
                sys.exit(1)

        elif args.command == "list-topics":
            list_topics(admin_client)

        elif args.command == "describe-topic":
            describe_topics(admin_client, args.topic)

        elif args.command == "delete-topic":
            success = delete_topics(admin_client, args.topic)

        elif args.command == "add-partitions":
            topic_partitions = parse_topic_partitions_string(args.topic_partitions)
            if not topic_partitions:
                logger.error("No valid topic:partition pairs provided")
                sys.exit(1)
            success = add_partitions(admin_client, topic_partitions)

        elif args.command == "describe-config":
            describe_topic_configs(admin_client, args.topic)

        elif args.command == "alter-config":
            configs = parse_config_string(args.config)
            if not configs:
                logger.error("No valid configuration pairs provided")
                sys.exit(1)
            success = alter_topic_configs(admin_client, args.topic, configs)

        elif args.command == "describe-cluster":
            describe_cluster(admin_client)

        elif args.command == "list-consumer-groups":
            list_consumer_groups(admin_client)

        elif args.command == "describe-consumer-group":
            describe_consumer_groups(admin_client, args.group)

        else:
            logger.error("Unknown command: %s", args.command)
            parser.print_help()
            sys.exit(1)

    except KeyboardInterrupt:
        logger.info("Operation interrupted by user")
        sys.exit(130)
    except Exception as e:
        logger.error("Unexpected error: %s", e, exc_info=True)
        sys.exit(1)
    finally:
        try:
            admin_client.close()
            logger.info("Admin client connection closed")
        except Exception:
            pass

    if not success:
        sys.exit(1)


if __name__ == "__main__":
    main()